import { Mastra, Agent } from '@mastra/core';
import { Memory } from '@mastra/memory';

const memory = new Memory();

const coder = new Agent({
  name: 'Coder',
  instructions: 'You are a professional TypeScript developer. Write clean, efficient, and well-documented TypeScript code.',
  model: {
    provider: 'OPENAI',
    name: 'gpt-4o-mini',
  },
  memory,
});

const reviewer = new Agent({
  name: 'Reviewer',
  instructions: 'You are a security and performance expert. Review TypeScript code for security vulnerabilities and performance bottlenecks.',
  model: {
    provider: 'OPENAI',
    name: 'gpt-4o-mini',
  },
  memory,
});

const supervisor = new Agent({
  name: 'Supervisor',
  instructions: 'You are a project manager. Coordinate the coder and reviewer to complete the user request. First ask the coder to write the code, then ask the reviewer to review it.',
  model: {
    provider: 'OPENAI',
    name: 'gpt-4o-mini',
  },
  memory,
  agents: [coder, reviewer],
});

export const mastra = new Mastra({
  agents: [coder, reviewer, supervisor],
});

