import { mastra } from './index';
import * as fs from 'fs';

async function main() {
  const supervisor = mastra.getAgent('supervisor');

  try {
    console.log('Sending request to supervisor...');
    const result = await supervisor.generate('Write a simple Express server and review it');

    const outputPath = '/home/user/project/output.txt';
    fs.writeFileSync(outputPath, result.text);
    console.log('Output written to output.txt');
  } catch (error) {
    console.error('Error running supervisor:', error);
    process.exit(1);
  }
}

